import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="d-flex">
      <nav className="sidebar d-flex flex-column">
        <div className="px-3 py-3 border-bottom border-secondary mb-2">
          <h5 className="mb-0 text-white">
            <i className="bi bi-heart-pulse-fill me-2 text-danger" />
            EHR System
          </h5>
          <small className="text-white-50">{user?.name}</small>
        </div>

        <NavLink to="/dashboard"><i className="bi bi-speedometer2 me-2" />Dashboard</NavLink>

        {(user?.role === 'admin' || user?.role === 'doctor') && (
          <NavLink to="/patients"><i className="bi bi-people me-2" />Patients</NavLink>
        )}

        <NavLink to="/appointments"><i className="bi bi-calendar-check me-2" />Appointments</NavLink>

        {(user?.role === 'admin' || user?.role === 'doctor') && (
          <NavLink to="/records/new"><i className="bi bi-file-earmark-plus me-2" />New Record</NavLink>
        )}

        <NavLink to="/profile"><i className="bi bi-person-circle me-2" />Profile</NavLink>

        <div className="mt-auto p-3">
          <button className="btn btn-outline-light btn-sm w-100" onClick={handleLogout}>
            <i className="bi bi-box-arrow-right me-2" />Logout
          </button>
        </div>
      </nav>

      <main className="main-content flex-grow-1">
        <Outlet />
      </main>
    </div>
  );
}
